    ;WITH src AS (
        SELECT
            seed.CodigoProveedor,
            seed.Rut,
            seed.Nombre,
            seed.Pais,
            seed.Region,
            seed.Comuna,
            seed.Distrito,
            seed.Calle,
            seed.Email,
            seed.OrganizacionCompra,
            seed.MonedaPedido,
            seed.CondicionPago,
            seed.Incoterm,
            seed.Sociedad,
            seed.CuentaAsociada,
            seed.Activo,
            FechaActualizacionSap = TRY_CONVERT(DATETIME2(3), seed.FechaActualizacionSapTexto)
        FROM #ProductorSeed seed
    )
    INSERT INTO [cfl].[Productor] (
        [CodigoProveedor],
        [Rut],
        [Nombre],
        [Pais],
        [Region],
        [Comuna],
        [Distrito],
        [Calle],
        [Email],
        [OrganizacionCompra],
        [MonedaPedido],
        [CondicionPago],
        [Incoterm],
        [Sociedad],
        [CuentaAsociada],
        [Activo],
        [FechaActualizacionSap],
        [FechaCreacion],
        [FechaActualizacion]
    )
    SELECT
        s.[CodigoProveedor],
        s.[Rut],
        s.[Nombre],
        s.[Pais],
        s.[Region],
        s.[Comuna],
        s.[Distrito],
        s.[Calle],
        s.[Email],
        s.[OrganizacionCompra],
        s.[MonedaPedido],
        s.[CondicionPago],
        s.[Incoterm],
        s.[Sociedad],
        s.[CuentaAsociada],
        s.[Activo],
        s.[FechaActualizacionSap],
        SYSUTCDATETIME(),
        SYSUTCDATETIME()
    FROM src s
    WHERE NOT EXISTS (
        SELECT 1
        FROM [cfl].[Productor] t
        WHERE t.[CodigoProveedor] = s.[CodigoProveedor]
    );

    DECLARE @filasInsertadas INT = @@ROWCOUNT;

    DROP TABLE #ProductorSeed;

    COMMIT TRANSACTION;
    PRINT CONCAT('Carga de productores completada. Filas insertadas: ', @filasInsertadas);
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
    IF OBJECT_ID('tempdb..#ProductorSeed') IS NOT NULL DROP TABLE #ProductorSeed;
    DECLARE @msg NVARCHAR(4000) = ERROR_MESSAGE();
    RAISERROR('Carga de productores fallida: %s', 16, 1, @msg);
END CATCH;
GO
